"              <iframe id="customizerIframe" src="" style="width:100%; height:calc(100% - 24px); border:none; display:none; background:transparent;" onload="const spinner = document.getElementById('customizerLoading'); if (spinner) spinner.style.display = 'none';"></iframe>
              <div id="customizerLoading" style="position:absolute; inset:24px 0 0 0; display:none; flex-direction:column; align-items:center; justify-content:center; background:#ffffff; z-index:100; font-family:system-ui,-apple-system,sans-serif;">
                <div style="width:36px; height:36px; border:4px solid #f3f3f3; border-top:4px solid var(--platform-accent, #7C3AED); border-radius:50%; animation:customizer-spin 1s linear infinite; margin-bottom:12px;"></div>
                <style>
                  @keyframes customizer-spin {
                    0% { transform: rotate(0deg); }
                    100% { transform: rotate(360deg); }
                  }
                </style>
                <div style="font-size:13px; font-weight:700; color:#1f2937;">Loading Page Builder...</div>
              </div>"
